import{_ as t,c as i,o as a,ag as o}from"./chunks/framework.DVUBUV_u.js";const h=JSON.parse('{"title":"Introduction","description":"","frontmatter":{"title":"Introduction","layout":"doc"},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),n={name:"index.md"};function r(s,e,l,d,u,c){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><h2 id="what-is-vue-inspector" tabindex="-1">What is Vue Inspector? <a class="header-anchor" href="#what-is-vue-inspector" aria-label="Permalink to &quot;What is Vue Inspector?&quot;">​</a></h2><p><strong>Vue Inspector</strong> is a tool for analyzing Vue applications at runtime without requiring access to source code, a local build, or a dedicated development environment.</p><p>The extension allows you to explore the application structure directly on the loaded page: inspect props, store data, network requests, and internal component state exactly as they exist while the application is running.</p><p>It is designed for scenarios where you need to quickly understand the current frontend state without relying on additional development tools.</p><hr><h2 id="why-use-vue-inspector" tabindex="-1">Why use Vue Inspector? <a class="header-anchor" href="#why-use-vue-inspector" aria-label="Permalink to &quot;Why use Vue Inspector?&quot;">​</a></h2><p>Vue Inspector helps simplify application analysis when standard browser tools are not sufficient or when faster access to runtime data is required.</p><p>Main capabilities:</p><ul><li>View component props in real time;</li><li>Inspect received and declared props;</li><li>Access store data without manually searching runtime structures;</li><li>Browse network requests in a structured format;</li><li>Jump quickly to related data inside the application;</li><li>Select components directly on the page using Inspect mode;</li><li>Filter and locate required data without manually traversing the DOM structure;</li></ul><hr><h2 id="how-is-vue-inspector-different-from-standard-devtools" tabindex="-1">How is Vue Inspector different from standard DevTools? <a class="header-anchor" href="#how-is-vue-inspector-different-from-standard-devtools" aria-label="Permalink to &quot;How is Vue Inspector different from standard DevTools?&quot;">​</a></h2><p>Unlike Vue Devtools, Vue Inspector is designed not only for local development but also for working with already running applications where:</p><ul><li>source code is unavailable;</li><li>no local project build is accessible;</li><li>production or test environments need to be explored quickly;</li><li>runtime data must be inspected without preparing a development environment;</li></ul><hr><h2 id="when-is-it-especially-useful" tabindex="-1">When is it especially useful? <a class="header-anchor" href="#when-is-it-especially-useful" aria-label="Permalink to &quot;When is it especially useful?&quot;">​</a></h2><p>Vue Inspector is particularly useful for:</p><ul><li>frontend application testing;</li><li>analyzing complex integrations;</li><li>investigating component behavior;</li><li>locating data transfer issues;</li><li>verifying reactive application state;</li></ul><hr><h2 id="additional-notes" tabindex="-1">Additional Notes <a class="header-anchor" href="#additional-notes" aria-label="Permalink to &quot;Additional Notes&quot;">​</a></h2><p>The project continues to evolve and gradually expands runtime analysis support for various frontend scenarios.</p>',21)])])}const f=t(n,[["render",r]]);export{h as __pageData,f as default};
